#!/bin/bash
# Reads prompt.txt params, patches evolution-core.js, runs training, outputs metrics
set -e
cd "$(dirname "$0")/.."

# Parse params from prompt.txt
source <(grep -E '^[A-Z_]+=.+$' .autoresearch/prompt.txt)

# Generate evolution-core.js with current params
cat > js/evolution-core.js << 'HEADER'
// Core evolution logic shared between visual (evolution.js) and headless (train.js)
// No Three.js dependency — pure math
// AUTO-GENERATED by autoresearch — do not edit manually during optimization

HEADER

cat >> js/evolution-core.js << EOF
// ─── Tournament Selection (k=${TOURNAMENT_K}) ───────────────
export function tournamentSelect(cars, k = ${TOURNAMENT_K}) {
  let best = null;
  for (let i = 0; i < k; i++) {
    const candidate = cars[Math.floor(Math.random() * cars.length)];
    if (!best || candidate.score > best.score) best = candidate;
  }
  return best;
}

// ─── Fitness Scoring ─────────────────────────────────
export function computeScore(car) {
  const progressScore = car.totalProgress * car.totalProgress;
  if (car.finished) {
    const refTime = ${FITNESS_REF_TIME};
    return progressScore + ${FITNESS_FINISH_BASE} + ${FITNESS_FINISH_RATIO} * (refTime / car.lapTime);
  }
  return progressScore;
}

// ─── Adaptive Mutation with Cooldown ─────────────────
export function computeAdaptiveMutation({
  bestScore,
  allTimeBest,
  stagnantGens,
  baseMutation,
  currentMutation,
}) {
  if (bestScore > allTimeBest) {
    return {
      allTimeBest: bestScore,
      stagnantGens: 0,
      mutationRate: baseMutation,
      improved: true,
      restart: false,
    };
  }

  const nextStagnant = stagnantGens + 1;
  let nextMutation = currentMutation;
  let restart = false;

  if (nextStagnant >= ${STAGNANT_RESTART_THRESHOLD}) {
    restart = true;
    nextMutation = baseMutation;
  } else if (nextStagnant >= ${STAGNANT_SEVERE_THRESHOLD}) {
    nextMutation = Math.min(${MUTATION_CAP_SEVERE}, currentMutation * ${MUTATION_MULT_SEVERE});
  } else if (nextStagnant >= ${STAGNANT_MILD_THRESHOLD}) {
    nextMutation = Math.min(${MUTATION_CAP_MILD}, currentMutation * ${MUTATION_MULT_MILD});
  }

  return {
    allTimeBest,
    stagnantGens: nextStagnant,
    mutationRate: nextMutation,
    improved: false,
    restart,
  };
}

// ─── Per-Individual Mutation Rate Tiers ──────────────
export function getTieredMutationRate(childIndex, totalCars, baseMutation) {
  const ratio = childIndex / totalCars;
  if (ratio < ${TIERED_LOW_RATIO}) return baseMutation * ${TIERED_LOW_MULT};
  if (ratio < ${TIERED_MID_RATIO}) return baseMutation * ${TIERED_MID_MULT};
  return baseMutation * ${TIERED_HIGH_MULT};
}

// ─── Legacy selector (kept for compatibility) ───────
export function selectTopPerformers(cars, numCars) {
  const scored = [...cars].sort((a, b) => b.score - a.score);
  const topCount = Math.max(1, Math.ceil(numCars / 5));
  return { scored, top: scored.slice(0, topCount) };
}
EOF

# Run training 3 times and take best
BEST_LAP=999
BEST_SCORE=0
SUM_AVG=0
SUM_FIN=0

for i in 1 2 3; do
  OUTPUT=$(node train.js --gens 300 --cars 50 2>&1)

  LAP=$(echo "$OUTPUT" | grep "Best lap:" | grep -oE '[0-9]+\.[0-9]+' | head -1)
  SCORE=$(echo "$OUTPUT" | grep "Best score:" | grep -oE '[0-9]+\.[0-9]+' | head -1)

  AVG=$(echo "$OUTPUT" | grep "Gen " | tail -50 | grep -oE 'avg: *[0-9]+\.[0-9]+' | sed 's/avg: *//' | awk '{s+=$1; n++} END{if(n>0) printf "%.1f", s/n; else print "0"}')
  FIN=$(echo "$OUTPUT" | grep "Gen " | tail -50 | grep -oE 'fin:[0-9]+' | sed 's/fin://' | awk '{s+=$1; n++} END{if(n>0) printf "%.1f", s/n; else print "0"}')

  [ -n "$SCORE" ] && (( $(echo "$SCORE > $BEST_SCORE" | bc -l 2>/dev/null || echo 0) )) && BEST_SCORE=$SCORE
  [ -n "$LAP" ] && (( $(echo "$LAP < $BEST_LAP" | bc -l 2>/dev/null || echo 0) )) && BEST_LAP=$LAP
  SUM_AVG=$(echo "${SUM_AVG:-0} + ${AVG:-0}" | bc -l 2>/dev/null || echo 0)
  SUM_FIN=$(echo "${SUM_FIN:-0} + ${FIN:-0}" | bc -l 2>/dev/null || echo 0)
done

AVG_PROGRESS=$(echo "$SUM_AVG / 3" | bc -l 2>/dev/null | head -c6 || echo "0")
AVG_FINISHERS=$(echo "$SUM_FIN / 3" | bc -l 2>/dev/null | head -c5 || echo "0")

echo "BEST_LAP=$BEST_LAP"
echo "BEST_SCORE=$BEST_SCORE"
echo "AVG_PROGRESS=$AVG_PROGRESS"
echo "AVG_FINISHERS=$AVG_FINISHERS"
